const crypto = require('crypto');
const h = $input.first().json.headers || {};
const auth = h.authorization || h.Authorization || '';
const token = auth.startsWith('Bearer ') ? auth.slice(7) : auth;
const body = $input.first().json.body || {};
const defaultCase = {symptoms:['severe headache','fever','neck stiffness','photophobia'],vitals:{temp_c:39.4,hr:112,bp_sys:128,bp_dia:82,rr:20,spo2:97},history:{age:28,sex:'F',conditions:[],medications:[]},labs:{wbc:14.2,crp:78}};
const c = (body.symptoms && body.symptoms.length) ? body : defaultCase;
const trace_id = crypto.randomBytes(16).toString('hex');
const root_span_id = crypto.randomBytes(8).toString('hex');
return [{ json: { token, case: c, trace_id, root_span_id, _t_start: Date.now() } }];

const tx = $('Extract Token & Case').first().json;
const c = tx.case;
const sx = (c.symptoms||[]).join(', ');
const v = c.vitals||{};
const vstr = `temp ${v.temp_c}C, HR ${v.hr}, BP ${v.bp_sys}/${v.bp_dia}, RR ${v.rr}, SpO2 ${v.spo2}`;
const labs = c.labs ? Object.entries(c.labs).map(([k,v])=>`${k}=${v}`).join(', ') : '';
const query = `Patient: ${sx}. Vitals: ${vstr}. Labs: ${labs}.`;
return [{ json: { case: c, query_text: query, trace_id: tx.trace_id, root_span_id: tx.root_span_id, _t_start: tx._t_start, _t_query: Date.now() } }];

let r = $input.first().json;
let vec = r.body !== undefined ? r.body : r;
if (Array.isArray(vec[0])) vec = vec[0];
if (vec.length !== 384) throw new Error('expected 384 dims, got '+vec.length);
const lit = '[' + vec.map(x => Number(x).toFixed(8)).join(',') + ']';
const prev = $('Build Query Text').first().json;
return [{ json: { ...prev, vector: lit, _t_embed_end: Date.now() } }];

const docs = $input.all().map(i => i.json);
const ctx = docs.map((d,i)=>`[doc ${i+1}] id=${d.id} source=${d.source||'n/a'} type=${d.evidence_type||'n/a'}
${(d.content||'').slice(0,2000)}`).join('

');
const evidence_ids = docs.map(d=>d.id);
const tx = $('Extract Token & Case').first().json;
const c = tx.case;
const sx = (c.symptoms||[]).join(', ');
const v = c.vitals||{};
const labs = c.labs ? Object.entries(c.labs).map(([k,v])=>`${k}=${v}`).join(', ') : 'none';
const h = c.history||{};
const userPrompt = `PATIENT CASE
Symptoms: ${sx}
Vitals: temp ${v.temp_c}C, HR ${v.hr}, BP ${v.bp_sys}/${v.bp_dia}, RR ${v.rr}, SpO2 ${v.spo2}
History: age ${h.age}, sex ${h.sex}, conditions ${(h.conditions||[]).join(',')||'none'}
Labs: ${labs}

RETRIEVED EVIDENCE
${ctx}

Return ONLY JSON.`;
const prev = $('Vector Literal').first().json;
return [{ json: { user_prompt: userPrompt, evidence_ids, docs, case: c, trace_id: tx.trace_id, root_span_id: tx.root_span_id, _t_start: tx._t_start, _t_embed_end: prev._t_embed_end, _t_retrieve_end: Date.now() } }];

