const r = $input.first().json;
const raw = r.choices?.[0]?.message?.content || '{}';
let parsed; try { parsed = JSON.parse(raw); } catch(e) { parsed = { diagnoses:[], reasoning:'parse_error', needs_reretrival:false }; }
const ctx = $('Format Context').first().json;
const usage = r.usage || {};
return [{ json: { initial: parsed, user_prompt_initial: ctx.user_prompt, evidence_ids: ctx.evidence_ids, docs: ctx.docs, case: ctx.case, trace_id: ctx.trace_id, root_span_id: ctx.root_span_id, _t_start: ctx._t_start, _t_embed_end: ctx._t_embed_end, _t_retrieve_end: ctx._t_retrieve_end, _t_diag_end: Date.now(), _diag_usage: usage, _diag_raw: raw } }];

const r = $input.first().json;
const raw = r.choices?.[0]?.message?.content || '{}';
let parsed; try { parsed = JSON.parse(raw); } catch(e) { parsed = { diagnoses:[], reasoning:'parse_error', needs_reretrival:false }; }
const prev = $('Parse Diagnosis').first().json;
const usage = r.usage || {};
return [{ json: { initial: prev.initial, reflection: parsed, evidence_ids: prev.evidence_ids, case: prev.case, trace_id: prev.trace_id, root_span_id: prev.root_span_id, _t_start: prev._t_start, _t_embed_end: prev._t_embed_end, _t_retrieve_end: prev._t_retrieve_end, _t_diag_end: prev._t_diag_end, _t_refl_end: Date.now(), _diag_usage: prev._diag_usage, _refl_usage: usage, _diag_input: prev.user_prompt_initial, _diag_output: prev._diag_raw, _refl_output: raw } }];

const j = $input.first().json;
const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
const allowed = new Set(j.evidence_ids);
const filt = (lst) => (lst||[]).map(d => ({...d, evidence_ids: (d.evidence_ids||[]).filter(e => uuidRe.test(e) && allowed.has(e))}));
const final_diagnoses = filt(j.reflection.diagnoses);
const crypto = require('crypto');
const case_id = (j.case && j.case.case_id) || crypto.randomUUID();
return [{ json: { ok:true, case_id, trace_id: j.trace_id, root_span_id: j.root_span_id, _t_start: j._t_start, _t_embed_end: j._t_embed_end, _t_retrieve_end: j._t_retrieve_end, _t_diag_end: j._t_diag_end, _t_refl_end: j._t_refl_end, _t_end: Date.now(), _diag_usage: j._diag_usage, _refl_usage: j._refl_usage, _diag_input: j._diag_input, _diag_output: j._diag_output, _refl_output: j._refl_output, doc_count: (j.evidence_ids||[]).length, initial_diagnosis: filt(j.initial.diagnoses), reflection_diagnosis: final_diagnoses, final_diagnosis: final_diagnoses, retrieved_evidence_ids: j.evidence_ids, needs_reretrival: !!j.reflection.needs_reretrival, disclaimer: 'Not a medical diagnosis; consult a clinician.' } }];

const crypto = require('crypto');
const j = $input.first().json;
const tid = j.trace_id;
const root = j.root_span_id;
const sid = () => crypto.randomBytes(8).toString('hex');
const iso = (ms) => new Date(ms).toISOString().replace('Z','000Z');
const RES = { attributes: { 'service.name': 'medrag_n8n', 'telemetry.sdk.language': 'python', 'telemetry.sdk.name': 'opentelemetry', 'telemetry.sdk.version': '1.29.0' }, schema_url: '' };
const baseSpan = (name, parent, t0, t1, attrs, events) => ({
  name, context: { trace_id: '0x'+tid, span_id: '0x'+sid(), trace_state: '[]' },
  kind: 'SpanKind.INTERNAL', parent_id: parent ? '0x'+parent : null,
  start_time: iso(t0), end_time: iso(t1),
  status: { status_code: 'OK' },
  attributes: { 'workflow.name': 'medrag_n8n', 'monocle_apptrace.version': '0.5.0', ...attrs },
  events: events || [], links: [], resource: RES
});
const evt = (name, ts, attrs) => ({ name, timestamp: iso(ts), attributes: attrs });
const embedSpan = (parent, t0, t1, query) => baseSpan('openai.embeddings.create', parent, t0, t1, { 'span.type':'embedding', 'entity.count':1, 'entity.1.name':'all-MiniLM-L6-v2', 'entity.1.type':'model.embedding.all-MiniLM-L6-v2' }, [evt('data.input', t0, { input: [query] }), evt('data.output', t1, { response: '[384-d vector]' })]);
const retrieveSpan = (parent, t0, t1, doc_count) => baseSpan('postgres.pgvector.search', parent, t0, t1, { 'span.type':'retrieval', 'entity.count':1, 'entity.1.name':'medicalrag.documents', 'entity.1.type':'vectorstore.pgvector', 'retrieval.doc_count': doc_count }, []);
const inferSpan = (parent, t0, t1, model, input, output, usage) => baseSpan('openai.resources.chat.completions.create', parent, t0, t1, { 'span.type':'inference', 'entity.count':2, 'entity.1.type':'inference.groq', 'entity.1.provider_name':'groq', 'entity.1.inference_endpoint':'https://api.groq.com/openai/v1', 'entity.2.name': model, 'entity.2.type':'model.llm.'+model }, [evt('data.input', t0, { input: [input] }), evt('data.output', t1, { response: [output] }), evt('metadata', t1, { completion_tokens: usage?.completion_tokens||0, prompt_tokens: usage?.prompt_tokens||0, total_tokens: usage?.total_tokens||0 })]);
const root_span = { name: 'workflow', context: { trace_id: '0x'+tid, span_id: '0x'+root, trace_state: '[]' }, kind: 'SpanKind.INTERNAL', parent_id: null, start_time: iso(j._t_start), end_time: iso(j._t_end), status: { status_code: 'OK' }, attributes: { 'workflow.name': 'medrag_n8n', 'span.type': 'workflow', 'entity.count': 1, 'entity.1.name': 'medrag_n8n', 'entity.1.type': 'workflow.generic', 'monocle_apptrace.version': '0.5.0', 'case_id': j.case_id, 'doc_count': j.doc_count, 'final_count': (j.final_diagnosis||[]).length, 'top_condition': (j.final_diagnosis||[])[0]?.condition || '', 'top_confidence': (j.final_diagnosis||[])[0]?.confidence || '' }, events: [], links: [], resource: RES };
const query_text = j._diag_input ? j._diag_input.split('\n')[0] : 'patient case';
const batch = [
  root_span,
  embedSpan(root, j._t_start, j._t_embed_end, query_text),
  retrieveSpan(root, j._t_embed_end, j._t_retrieve_end, j.doc_count),
  inferSpan(root, j._t_retrieve_end, j._t_diag_end, 'llama-3.1-8b-instant', j._diag_input || '', j._diag_output || '', j._diag_usage),
  inferSpan(root, j._t_diag_end, j._t_refl_end, 'llama-3.1-8b-instant', 'reflection critique', j._refl_output || '', j._refl_usage)
];
return [{ json: { batch } }];
